member.example:
Bind the RectTransform size delta using a serialized binder field — the target RectTransform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RectTransformSizeDeltaBinder _size;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _size;
    }


Bind the RectTransform size delta by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private RectTransform _target;
        
        private RectTransformSizeDeltaBinder Size =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _size;
    }

Switch the RectTransform size delta between two values using a serialized binder field — the target RectTransform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RectTransformSizeDeltaSwitcherBinder _isExpanded;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }


Switch the RectTransform size delta between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RectTransform _target;
        
        [SerializeField]
        private Vector2 _expandedSize;
        
        [SerializeField]
        private Vector2 _collapsedSize;
        
        private RectTransformSizeDeltaSwitcherBinder IsExpanded => new(
            _target, _expandedSize, _collapsedSize);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isExpanded;
    }
